import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer } from 'lucide-react';
import './App.css';

const API_KEY = "તમારો_OPENWEATHER_API_KEY_અહીં_લખો"; 

function App() {
  const [city, setCity] = useState('Ahmedabad');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      // 1. Current Weather API
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      // 2. 5 Days Forecast API
      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      // દર 24 કલાકની એક ડેટા એન્ટ્રી ફિલ્ટર કરવા (બપોરે 12 વાગ્યાની)
      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('સિટી જડ્યું નહીં! ફરીથી ચેક કરો.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  // વેધર કન્ડિશન પ્રમાણે આઇકોન બદલવા માટેનું ફંક્શન
  const getWeatherIcon = (main) => {
    switch (main) {
      case 'Clear': return <Sun className="weather-icon text-yellow-400" size={64} />;
      case 'Clouds': return <Cloud className="weather-icon text-gray-300" size={64} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="weather-icon text-blue-400" size={64} />;
      default: return <Sun className="weather-icon" size={64} />;
    }
  };

  return (
    <div className="app-container">
      <div className="weather-card">
        {/* Search Bar */}
        <form onSubmit={handleSearch} className="search-form">
          <input 
            type="text" 
            placeholder="સિટીનું નામ લખો..." 
            value={city}
            onChange={(e) => setCity(e.target.value)}
          />
          <button type="submit"><Search size={20} /></button>
        </form>

        {loading && <div className="loader">લોડિંગ થઈ રહ્યું છે...</div>}
        {error && <div className="error-msg">{error}</div>}

        {/* Current Weather Display */}
        {weatherData && !loading && !error && (
          <div className="main-weather">
            <h2 className="location">{weatherData.name}, {weatherData.sys.country}</h2>
            <div className="weather-info-block">
              {getWeatherIcon(weatherData.weather[0].main)}
              <h1 className="temp">{Math.round(weatherData.main.temp)}°C</h1>
            </div>
            <p className="description">{weatherData.weather[0].description.toUpperCase()}</p>

            {/* Extra Stats */}
            <div className="stats-grid">
              <div className="stat-item">
                <Thermometer size={20} />
                <span>Feels like: {Math.round(weatherData.main.feels_like)}°C</span>
              </div>
              <div className="stat-item">
                <Droplets size={20} />
                <span>Humidity: {weatherData.main.humidity}%</span>
              </div>
              <div className="stat-item">
                <Wind size={20} />
                <span>Wind: {weatherData.wind.speed} m/s</span>
              </div>
            </div>

            {/* Forecast Section */}
            <h3 className="forecast-title">આગામી દિવસોની આગાહી</h3>
            <div className="forecast-container">
              {forecastData.map((day, idx) => (
                <div key={idx} className="forecast-item">
                  <p className="forecast-date">{new Date(day.dt * 1000).toLocaleDateString('en-US', { weekday: 'short' })}</p>
                  {getWeatherIcon(day.weather[0].main)}
                  <p className="forecast-temp">{Math.round(day.main.temp)}°C</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
